// Worked focus: httpsts-compression-vary-secrets — Negotiate content coding, emit correct Vary, bound decoded size, avoid secret-dependent compression, and preserve streaming backpressure.
// Evidence: httpsts-worked-http-server-ts-fields-representations-cache-3
// Competency: httpsts-worked-http-server-ts-fields-representations-cache-3.
// Case 5798: privacy-sensitive records API using conditional requests.
// Operating constraint: retain a screen-reader-readable decision trace.
// Changed case: change the tenant and prove denial before repository access.
function worked_http_server_ts_fields_representations_cache_3(acceptJson: boolean, etagMatches: boolean, privateData: boolean): { status: number; cacheControl: string; vary: string } {
  if (!acceptJson) return { status: 406, cacheControl: "no-store", vary: "Accept" };
  const cacheControl = privateData ? "private, no-store" : "public, max-age=60";
  const status = etagMatches ? 304 : 200;
  return { status, cacheControl, vary: "Accept, Accept-Encoding" };
}

